            target_boundary = OpTxInputDaaScore(this.activeInputIndex) + RANDOM_DELAY_DAA;
        }
        require(parent_daa < target_boundary && target_daa >= target_boundary);
        require(parent_daa < target_daa);
        require(byte[32](target_before_daa.slice(18, 50)) == parent_hash);
        require(blockHash(parent_before_daa, parent_daa, parent_blue_score, parent_blue_work, parent_pruning_point) == parent_hash);

        byte[32] target_hash = blockHash(target_before_daa, target_daa, target_blue_score, target_blue_work, target_pruning_point);
        byte[32] seqcommit = byte[32](OpChainblockSeqCommit(target_hash));
        byte[32] seed = sha256(byte[](ticket_root) + byte[](target_hash) + byte[](seqcommit));
        int seed_0 = OpBin2Num(seed.slice(0, 1) + 0x00);
        int seed_1 = OpBin2Num(seed.slice(1, 2) + 0x00);
        int seed_2 = OpBin2Num(seed.slice(2, 3) + 0x00);
        int seed_3 = OpBin2Num(seed.slice(3, 4) + 0x00);
        int seed_4 = OpBin2Num(seed.slice(4, 5) + 0x00);
        int seed_5 = OpBin2Num(seed.slice(5, 6) + 0x00);
        int seed_6 = OpBin2Num(seed.slice(6, 7) + 0x00);
        int winner_from_seed = (
            seed_0 + seed_1 * 256 + seed_2 * 65536 + seed_3 * 16777216 +
            seed_4 * 4294967296 + seed_5 * 1099511627776 + seed_6 * 281474976710656
        ) % sold_tickets;

        require(winner_ticket_id == winner_from_seed);
        require(winner_batch_index >= 0 && winner_batch_index < sold_batches);
        require(winner_batch_start >= 0 && winner_batch_start <= winner_ticket_id);
        require(winner_ticket_id < winner_batch_start + winner_batch_count);
        require(merkleRoot(ticketBatchLeaf(winner_pubkey, winner_batch_start, winner_batch_count), winner_batch_index, winner_proof) == ticket_root);

        int prize = ticket_price * sold_tickets;
        int creator_refund = tx.inputs[this.activeInputIndex].value - prize - finalize_fee;
        require(creator_refund >= 0);
        require(tx.outputs.length == 2);
        require(tx.outputs[0].scriptPubKey == byte[](new ScriptPubKeyP2PK(winner_pubkey)));
        require(tx.outputs[0].value == prize);
        require(tx.outputs[1].scriptPubKey == byte[](new ScriptPubKeyP2PK(pubkey(creator_pubkey))));
        require(tx.outputs[1].value == creator_refund);
    }

    entrypoint function startRefund(int refund_transition_fee, byte[] refund_prefix, byte[] refund_suffix) {
        require(tx.locktime >= refund_after_daa);
        require(sold_tickets > 0 && sold_batches > 0);
        require(refund_cursor == 0 && refund_batch_cursor == 0);
        require(OpAuthOutputCount(this.activeInputIndex) == 1);
        require(OpAuthOutputIdx(this.activeInputIndex, 0) == 0);
        require(tx.outputs.length == 1);
        require(refund_transition_fee > 0 && refund_transition_fee <= MAX_REFUND_TRANSITION_FEE);
        require(tx.outputs[0].value == tx.inputs[this.activeInputIndex].value - refund_transition_fee);
        RefundState next_refund = {
            ticket_price: ticket_price,
            creator_pubkey: creator_pubkey,
            sold_tickets: sold_tickets,
            sold_batches: sold_batches,
            ticket_root: ticket_root,
            refund_cursor: 0,
            refund_batch_cursor: 0
        };
        validateOutputStateWithTemplate(0, next_refund, refund_prefix, refund_suffix, REFUND_TEMPLATE);
    }
}
